var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"SHIELD_ADMIN_NAMED_NULL","text":{"KOREA":"그만두시죠, 이수연님.","JPN":"おやめください、カナミ・キズナ殿。","ENG":"That's enough, ma'am.","TWN":"請住手，李秀妍小姐。"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"SHIELD_ADMIN_NAMED_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"당신들......?","JPN":"あなたたちは……？","ENG":"You guys?","TWN":"你們是……？"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_NULL","text":{"KOREA":"하하, 펜릴 전대의 말괄량이 에이스 아니십니까.","JPN":"ハハッ、フェンリル戦隊のお転婆エース殿ではありませんか。","ENG":"Hah hah, look who's here. The tomboy ace of the Fenrir Division.","TWN":"哈哈，這不是芬里爾戰隊的潑辣王牌嗎。"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"SHIELD_ADMIN_NAMED_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_NULL","text":{"KOREA":"못 보던 사이에 많이 변하셨네요. 그래도 저희 대장을 괴롭히시면 안 되죠.","JPN":"しばらく見ない間に立派になられましたね。\\nしかし、うちの隊長をいじめてもらっては困りますぞ。","ENG":"You sure changed a lot since the last time we saw you. That doesn't mean you can bully our Commander around.","TWN":"好久沒看到妳了，妳變了好多啊。但就算這樣，妳也不可以為難我們隊長啊。"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"SHIELD_ADMIN_NAMED_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"예고르......? 발레리......?","JPN":"イェゴール……？　ヴァレリー……？","ENG":"Yegor? Valeriy?","TWN":"伊高爾……？瓦萊里……？"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"게다가......","JPN":"それに……","ENG":"And...","TWN":"還有……"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"한숨 푹 자고 일어난 것 같은데, 오랜만이라고 인사하려니 이상하네.","JPN":"どうやらぐっすり眠っちゃってたみたいだけど、\\n久しぶりって挨拶するのも何だか変な気がするわ。","ENG":"I feel like I just got up from a nap, so it feels weird to say long time no see.","TWN":"我好像只是睡了一下而已，說好久不見感覺真奇怪。"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"그동안 고생 많았지, 류드밀라?","JPN":"今まで一人で大変だったでしょう？　\\nよく頑張ったわね、リュドミラちゃん。","ENG":"I bet you've been through a heck of a ride, huh, Lyudmila?","TWN":"這段時間妳一定吃了不少苦吧，盧德米拉？"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"알렉스까지......?","JPN":"アレックスまで……？","ENG":"Alex too?","TWN":"連雅蕾克絲都……？"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"당신들, 어떻게 여기에 나와 있는 겁니까?","JPN":"あなたたち、どうやってここに出られたのですか？","ENG":"How did you guys get out here?","TWN":"你們，怎麼都出來了？"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"SHIELD_ADMIN_NAMED_NULL","text":{"KOREA":"그간의 사정은 관리자님께 모두 들었습니다.","JPN":"今までの事情はすべて管理者殿からご説明いただきました。","ENG":"The Administrator told us about everything.","TWN":"這段時間的事情，我們都聽管理者大人說了。"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"SHIELD_ADMIN_NAMED_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SHIELD_ADMIN_NAMED_NULL","text":{"KOREA":"전대장님이 그림자로 바뀌었을지도 모른다는 추측까지 전부요.","JPN":"戦隊長がシャドウに変異したかもしれないという\\n推測も含め、すべてをです。","ENG":"Even about the speculation that the Commander here may have turned into a Shadow.","TWN":"包括隊長有可能已經變成暗影了這件事。"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"SHIELD_ADMIN_NAMED_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그걸 알면서도...... 그녀를 당신들의 대장으로 인정한다는 겁니까?","JPN":"それをわかっていながら……\\n彼女をあなた方の隊長と認めるのですか？","ENG":"You know that already... and you still choose to accept her as your Commander?","TWN":"既然你們都知道了……還要承認她是你們的隊長嗎？"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SHIELD_ADMIN_NAMED_NULL","text":{"KOREA":"안 될 것 있습니까?","JPN":"何か問題でも？","ENG":"Sure, why not?","TWN":"有什麼不可以的嗎？"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"SHIELD_ADMIN_NAMED_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"SHIELD_ADMIN_NAMED_NULL","text":{"KOREA":"이수연 님은 잘 모르실 수도 있겠지만, 저희 전대원은 대부분 일반인입니다.","JPN":"カナミ・キズナ殿はご存知ないかもしれませんが、\\n我が戦隊はほとんどが一般人です。","ENG":"You may not know this, but most of the division's members are regular folks.","TWN":"李秀妍小姐可能不知道，但我們的隊員大部分都是普通人。"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"SHIELD_ADMIN_NAMED_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"SHIELD_ADMIN_NAMED_NULL","text":{"KOREA":"누구든 침식 증후군에 시달릴 수 있다는 것쯤은 각오하고 있어요.","JPN":"誰もが侵食症候群に冒される可能性がある。それくらい\\n覚悟の上なのです。","ENG":"We know in the back of our minds that any one of us could suffer from Corruption syndrome.","TWN":"我們早就做好了隨時患上侵蝕症候群的心理準備。"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"SHIELD_ADMIN_NAMED_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_NULL","text":{"KOREA":"그래서 저희는 마지막까지 옆에 있는 동료를 믿어 주기로 했습니다.","JPN":"そして我々は最後の瞬間まで隣にいる仲間を信じると決めました。","ENG":"So we've decided to put our trust in whoever sticks with us till the very end.","TWN":"因此，我們決定直到最後，都要相信身邊的同伴。"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"SHIELD_ADMIN_NAMED_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};